// Extrai dados e converte data/hora BR para ISO 8601 com fuso de Brasília (-03:00)
const body = $input.first().json.body || $input.first().json;

const dateStr = body.date || '';
const timeStr = body.time || '09:00';

// Converte DD/MM/YYYY + HH:MM → ISO com offset de Brasília
// SEM o -03:00 o n8n interpretaria como UTC (3h adiantado)
let scheduleISO = '';
if (dateStr && dateStr !== 'A definir') {
  const parts = dateStr.split('/');
  if (parts.length === 3) {
    scheduleISO = `${parts[2]}-${parts[1]}-${parts[0]}T${timeStr}:00-03:00`;
  }
}

// Se a data já passou (em BRT) ou não foi definida, publica em 30 segundos
if (!scheduleISO || new Date(scheduleISO) <= new Date()) {
  const soon = new Date(Date.now() + 30000);
  scheduleISO = soon.toISOString(); // já vem em UTC, o n8n entende
}

return [{
  json: {
    igAccountId:  body.igAccountId  || '',
    fbToken:      body.fbToken      || '',
    type:         body.type         || 'imagem',
    mediaUrl:     body.mediaUrl     || '',
    slideUrls:    body.slideUrls    || [],
    coverUrl:     body.coverUrl     || '',
    caption:      body.caption      || '',
    scheduleISO
  }
}];

// Carrossel: cria um container para cada slide, depois cria o container do carrossel
const { igAccountId, fbToken, slideUrls, caption } = $input.first().json;

if (!slideUrls || slideUrls.length === 0) {
  throw new Error('Carrossel sem slides. Verifique se o post tem URLs de imagens.');
}

// Passo 1: criar container para cada slide individualmente
const childIds = [];
for (let i = 0; i < slideUrls.length; i++) {
  const url = slideUrls[i];
  if (!url) continue;

  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v22.0/${igAccountId}/media`,
    qs: { access_token: fbToken },
    body: {
      image_url: url,
      is_carousel_item: 'true',
      access_token: fbToken
    },
    json: true
  });

  if (res.error) {
    throw new Error(`Slide ${i + 1}: ${res.error.message}`);
  }
  if (!res.id) {
    throw new Error(`Slide ${i + 1}: sem ID retornado. Verifique se a URL é pública: ${url}`);
  }
  childIds.push(res.id);
}

if (childIds.length === 0) {
  throw new Error('Nenhum slide válido processado.');
}

// Passo 2: criar container do carrossel com os IDs dos slides
const carousel = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://graph.facebook.com/v22.0/${igAccountId}/media`,
  qs: { access_token: fbToken },
  body: {
    media_type: 'CAROUSEL',
    children: childIds.join(','),
    caption: caption || '',
    access_token: fbToken
  },
  json: true
});

if (carousel.error) {
  throw new Error(`Carrossel: ${carousel.error.message}`);
}

return [{ json: { id: carousel.id, fbToken, igAccountId } }];

// Aguarda o container ficar FINISHED (máx 60s — 20x com intervalo de 3s)
const containerId = $input.first().json.id;

// Pega token e igAccountId dos dados que vieram do Preparar Dados
// O Switch preserva o item original, então pegamos do nó anterior na cadeia
const data = $input.first().json;
const fbToken = data.fbToken || $('Preparar Dados').first().json.fbToken;
const igAccountId = data.igAccountId || $('Preparar Dados').first().json.igAccountId;

if (!containerId) {
  throw new Error('Container ID não encontrado. Verifique se o token é válido e a URL da mídia está acessível (use Dropbox com dl=1).');
}

let statusCode = '';
for (let i = 0; i < 20; i++) {
  await new Promise(r => setTimeout(r, 3000));
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://graph.facebook.com/v22.0/${containerId}`,
    qs: { fields: 'status_code,status', access_token: fbToken }
  });
  statusCode = res.status_code || '';
  if (statusCode === 'FINISHED') break;
  if (statusCode === 'ERROR') {
    throw new Error(`Instagram rejeitou a mídia: ${res.status || 'formato inválido'}. Use JPG/PNG para imagens e MP4 para vídeos. A URL deve ser pública (use Dropbox com dl=1).`);
  }
}

if (statusCode !== 'FINISHED') {
  throw new Error('Tempo esgotado (60s). Arquivo muito grande ou formato não suportado.');
}

return [{ json: { containerId, fbToken, igAccountId } }];
